import { Configuration, OpenAIApi } from "openai";

const configuration = new Configuration({
    apiKey: process.env.OPENAI_API_KEY, // Note: Consider better key management
});
const openai = new OpenAIApi(configuration);

export const generateDesignFromStory = async (story: string, style: string) => {
  try {
    const prompt = `Create a visually stunning image composition based on the following story, adhering to the specified style: Story: ${story}. Style: ${style}.`;
    const response = await openai.createImage({
      prompt,
      n: 1,
      size: "1024x1024",
    });

    return response.data.data[0].url;
  } catch (error: any) {
    if (error.response) {
      console.error(error.response.status);
      console.error(error.response.data);
    } else {
      console.error(error.message);
    }
    return null;
  }
