    model: ReasoningModelKey
): Promise<string> => {
    const ai = getAi();
    const langMap: Record<StoryLanguageKey, string> = {
        thai: 'Thai',
        english: 'English',
        contextual: 'contextual',
    };
    const prompt = `Continue this story with ONE sentence. Lang: ${langMap[language]}. Style: ${style}.\nStory: ${story}`;
    const response = await ai.models.generateContent({
        model,
        contents: prompt,
    });
    return (response.text || "").trim();
};

export const generateStoryCaption = async (story: string, model: ReasoningModelKey, language: 'English' | 'Thai' = 'English', maxLength: number = 60): Promise<string> => {
    const ai = getAi();
    const lang = language === 'Thai' ? 'Thai' : 'English';
    const prompt = `Create a catchy caption for this story in ${lang}. Max ${maxLength} characters. Respond with only the caption text.\nStory: ${story}`;
    const response = await ai.models.generateContent({
        model,
        contents: prompt,
    });
    return (response.text || "").trim();
};

export const polishStory = async (story: string, model: ReasoningModelKey): Promise<string> => {
    const ai = getAi();
    const prompt = `Rewrite this story elegantly. Do not change plot.\nStory: ${story}`;
    const response = await ai.models.generateContent({
        model,
        contents: prompt,
    });
    return (response.text || "").trim();
};

export const translateStory = async (story: string, targetLanguage: 'Thai' | 'English', model: ReasoningModelKey): Promise<string> => {
    const ai = getAi();
    const prompt = `Translate this into ${targetLanguage}:\n${story}`;
    const response = await ai.models.generateContent({
        model,
        contents: prompt,
    });
    return (response.text || "").trim();
};

export const generateDesignFromStory = async (story: string, styleName: string, model: ReasoningModelKey): Promise<string> => {
    const ai = getAi();
    const prompt = `Create an image prompt based on this story in ${styleName} style.\nStory: ${story}`;
    const response = await ai.models.generateContent({
        model,
        contents: prompt,
    });
    return (response.text || "").trim();
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
    generateFromText, 
    generateFromImageAndText, 
    describeImage, 
    suggestCaption, 
    enhancePrompt, 
    generateConcept, 
    expandImage,
    updateActiveApiKey
} from './services/geminiService';
import { ASPECT_RATIOS, IMAGE_STYLES, IMAGE_MODELS, REASONING_MODELS, AspectRatio, ImageStyleKey, ImageModelKey, ReasoningModelKey } from './constants';
import Spinner from './components/Spinner';
import ImagePlaceholder from './components/ImagePlaceholder';
import ReferenceImages from './components/ReferenceImages';
import ImageCard from './components/ImageCard';
import { blobToBase64 } from './utils/imageUtils';
import PromptActions from './components/PromptActions';
import StoryWriter from './components/StoryWriter';

declare global {
    interface AIStudio {
        hasSelectedApiKey: () => Promise<boolean>;
        openSelectKey: () => Promise<void>;
    }
}

const App: React.FC = () => {
    // API Key Management State
    const [apiKeyInput, setApiKeyInput] = useState<string>('');
    const [statusMessage, setStatusMessage] = useState<string>('');

    const [prompt, setPrompt] = useState<string>('');
    const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
    const [style, setStyle] = useState<ImageStyleKey>('photorealistic');
    const [imageModel, setImageModel] = useState<ImageModelKey>('gemini-2.5-flash-image');
    const [reasoningModel, setReasoningModel] = useState<ReasoningModelKey>('gemini-3-flash-preview');
    const [maxCaptionLength, setMaxCaptionLength] = useState<number>(60);
    const [images, setImages] = useState<string[]>([]);
    const [referenceImages, setReferenceImages] = useState<string[]>([]);
    const [loading, setLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [loadingCount, setLoadingCount] = useState<number>(0);
    const [processingAction, setProcessingAction] = useState<string | null>(null);
    const [promptActionLoading, setPromptActionLoading] = useState<string | null>(null);
    const promptTextareaRef = useRef<HTMLTextAreaElement>(null);

    // Initialize API Key from storage or env
    useEffect(() => {
        const savedKey = localStorage.getItem('user_api_key');
        const defaultKey = process.env.API_KEY;

        if (savedKey) {
            setApiKeyInput(savedKey);
            updateActiveApiKey(savedKey);
        } else if (defaultKey && defaultKey !== 'PLACEHOLDER_API_KEY' && defaultKey.length > 5) {
            setApiKeyInput(defaultKey);
            updateActiveApiKey(defaultKey);
        } else {
            setApiKeyInput('no API key');
        }
    }, []);

    const handleSendKey = () => {
        if (!apiKeyInput || apiKeyInput === 'no API key' || apiKeyInput.trim() === '') {
            setError("Please enter a valid API key.");
            return;
        }
        localStorage.setItem('user_api_key', apiKeyInput.trim());
        updateActiveApiKey(apiKeyInput.trim());
        setStatusMessage("Applied & Saved!");
        setTimeout(() => setStatusMessage(""), 3000);
    };

    const handleCopyKey = () => {
        if (apiKeyInput && apiKeyInput !== 'no API key') {
            navigator.clipboard.writeText(apiKeyInput);
            setStatusMessage("Copied!");
            setTimeout(() => setStatusMessage(""), 2000);
        }
    };

    const handleClearKey = () => {
        setApiKeyInput('');
        localStorage.removeItem('user_api_key');
        updateActiveApiKey(process.env.API_KEY || '');
        setStatusMessage("Cleared.");
        setTimeout(() => setStatusMessage(""), 2000);
    };

    const handleGenerate = useCallback(async (count: 1 | 4) => {
        if (!prompt.trim()) {
            setError("Please enter a prompt.");
            return;
        }

        const hasKey = localStorage.getItem('user_api_key') || (process.env.API_KEY && process.env.API_KEY !== 'PLACEHOLDER_API_KEY');
        if (!hasKey && imageModel === 'gemini-3-pro-image-preview') {
            try {
                const nativeKey = await window.aistudio.hasSelectedApiKey();
                if (!nativeKey) await window.aistudio.openSelectKey();
            } catch (err) {
                setError("API Key is required. Please set it in the field above.");
                return;
            }
        }

        setLoading(true);
        setError(null);
        setImages([]);

        const isGeminiModel = imageModel === 'gemini-2.5-flash-image' || imageModel === 'gemini-3-pro-image-preview';
        let effectiveCount = (referenceImages.length > 0 || isGeminiModel) ? 1 : count;
        setLoadingCount(effectiveCount);

        try {
            let generatedImages: string[];
            if (referenceImages.length > 0) {
                 generatedImages = await generateFromImageAndText(prompt, referenceImages);
            } else {
                 generatedImages = await generateFromText(prompt, effectiveCount as 1 | 4, aspectRatio, style, imageModel);
            }
            setImages(generatedImages);
        } catch (err) {
            if (err instanceof Error) {
                if (err.message.includes("Requested entity was not found") || err.message.includes("API_KEY_INVALID")) {
                     try {
                        setError("Invalid API Key. Please update the key in the field above.");
                        const controls = document.body;
                        controls.scrollIntoView({ behavior: 'smooth', block: 'start' });
                    } catch (e) {
                        setError("API Error: " + err.message);
                    }
                } else {
                    setError(err.message);
                }
            } else {
                setError("An unknown error occurred.");
            }
        } finally {
            setLoading(false);
            setLoadingCount(0);
        }
    }, [prompt, aspectRatio, style, imageModel, referenceImages]);

    const handleSetReference = useCallback((imageSrc: string) => {
        if (referenceImages.length < 4) {
            setReferenceImages(prev => [...prev, imageSrc]);
        } else {
            setError("You can only have a maximum of 4 reference images.");
        }
    }, [referenceImages.length]);

    const handleRemoveReference = useCallback((indexToRemove: number) => {
        setReferenceImages(prev => prev.filter((_, index) => index !== indexToRemove));
    }, []);

    const handleUploadReference = useCallback(async (file: File) => {
        if (!file.type.startsWith('image/')) {
            setError("Please upload a valid image file.");
            return;
        }
        try {
            const base64 = await blobToBase64(file);
            handleSetReference(base64 as string);
        } catch (err) {
            setError("Failed to read the image file.");
        }
    }, [handleSetReference]);

    const handleInsertRefTag = useCallback((tag: string) => {
        const textarea = promptTextareaRef.current;
        if (textarea) {
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const text = textarea.value;
            const newText = `${text.substring(0, start)} ${tag} ${text.substring(end)}`;
            setPrompt(newText);
            textarea.focus();
            textarea.selectionStart = textarea.selectionEnd = start + tag.length + 2;
        }
    }, []);

    const handleDescribe = useCallback(async (imageSrc: string, index: number) => {
        setProcessingAction(`describe-${index}`);
        setError(null);
        try {
            const description = await describeImage(imageSrc, reasoningModel);
            setPrompt(description);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setProcessingAction(null);
        }
    }, [reasoningModel]);

    const handleCaption = useCallback(async (imageSrc: string, index: number) => {
        setProcessingAction(`caption-${index}`);
        setError(null);
        try {
            const caption = await suggestCaption(imageSrc, reasoningModel, maxCaptionLength);
            setReferenceImages([imageSrc]);
            setPrompt(`Recreate the image in [ref-1], but add the following text as a caption: "${caption}". The caption should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The text should be clear and readable on a mobile screen.`);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setProcessingAction(null);
        }
    }, [reasoningModel, maxCaptionLength]);

    const handleRemoveText = useCallback(async (imageSrc: string, index: number) => {
        setProcessingAction(`remove-text-${index}`);
        setError(null);
        const newPrompt = `Analyze the image provided in [ref-1] and remove all text, words, characters and logos. Reconstruct the areas where the text was removed to look natural and seamless with the rest of the image.`;
        const newReferenceImages = [imageSrc];
        setPrompt(newPrompt);
        setReferenceImages(newReferenceImages);
        setLoading(true);
        setImages([]);
        setLoadingCount(1);
        try {
            const generatedImages = await generateFromImageAndText(newPrompt, newReferenceImages);
            setImages(generatedImages);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoading(false);
            setLoadingCount(0);
            setProcessingAction(null);
        }
    }, []);

    const handleExpandImage = useCallback(async (imageSrc: string, index: number, targetAspectRatio: AspectRatio) => {
        setProcessingAction(`expand-${index}`);
        setLoading(true);
        setError(null);
        setImages([]);
        setLoadingCount(1);
        setAspectRatio(targetAspectRatio);
        try {
            const expandedImages = await expandImage(imageSrc, targetAspectRatio);
            setImages(expandedImages);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoading(false);
            setLoadingCount(0);
            setProcessingAction(null);
            setAspectRatio('16:9');
        }
    }, []);

    const handleCopyPrompt = () => {
        if (!prompt.trim()) return;
        navigator.clipboard.writeText(prompt);
    };

    const handleClearPrompt = () => {
        setPrompt('');
    };

    const handleDescribeRef1 = useCallback(async () => {
        if (referenceImages.length === 0) {
            setError("No reference image available to describe.");
            return;
        }
        setPromptActionLoading('describe-ref-1');
        setError(null);
        try {
            const description = await describeImage(referenceImages[0], reasoningModel);
            setPrompt(description);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setPromptActionLoading(null);
        }
    }, [referenceImages, reasoningModel]);

    const handleCaptionRef1 = useCallback(async () => {
        if (referenceImages.length === 0) {
            setError("No reference image available to caption.");
            return;
        }
        setPromptActionLoading('caption-ref-1');
        setError(null);
        try {
            const caption = await suggestCaption(referenceImages[0], reasoningModel, maxCaptionLength);
            setReferenceImages([referenceImages[0]]);
            setPrompt(`Recreate the image in [ref-1], but add the following text as a caption: "${caption}". The caption should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The text should be clear and readable on a mobile screen.`);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setPromptActionLoading(null);
        }
    }, [referenceImages, reasoningModel, maxCaptionLength]);

    const handleRemoveTextRef1 = useCallback(async () => {
        if (referenceImages.length === 0) {
            setError("No reference image available to process.");
            return;
        }
        setPromptActionLoading('remove-text-ref-1');
        setError(null);
        const newPrompt = `Analyze the image provided in [ref-1] and remove all text, words, characters and logos. Reconstruct the areas where the text was removed to look natural and seamless with the rest of the image.`;
        const newReferenceImages = [referenceImages[0]];
        setPrompt(newPrompt);
        setReferenceImages(newReferenceImages);
        setLoading(true);
        setImages([]);
        setLoadingCount(1);
        try {
            const generatedImages = await generateFromImageAndText(newPrompt, newReferenceImages);
            setImages(generatedImages);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoading(false);
            setLoadingCount(0);
            setPromptActionLoading(null);
        }
    }, [referenceImages]);

    const handleExpandRef1 = useCallback(async (targetAspectRatio: AspectRatio) => {
        if (referenceImages.length === 0) {
            setError("No reference image available to expand.");
            return;
        }
        setPromptActionLoading('expand-ref-1');
        setLoading(true);
        setError(null);
        setImages([]);
        setLoadingCount(1);
        setAspectRatio(targetAspectRatio);
        try {
            const expandedImages = await expandImage(referenceImages[0], targetAspectRatio);
            setImages(expandedImages);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoading(false);
            setLoadingCount(0);
            setPromptActionLoading(null);
            setAspectRatio('16:9');
        }
    }, [referenceImages]);

    const handleEnhancePrompt = useCallback(async () => {
        if (!prompt.trim()) {
            setError("Prompt is empty, nothing to enhance.");
            return;
        }
        setPromptActionLoading('enhance');
        setError(null);
        try {
            const enhanced = await enhancePrompt(prompt, reasoningModel);
            setPrompt(enhanced);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setPromptActionLoading(null);
        }
    }, [prompt, reasoningModel]);

    const handleConcept = useCallback(async () => {
        if (!prompt.trim()) {
            setError("Prompt is empty, cannot generate concept.");
            return;
        }
        setPromptActionLoading('concept');
        setError(null);
        try {
            const concept = await generateConcept(prompt, reasoningModel);
            setPrompt(concept);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setPromptActionLoading(null);
        }
    }, [prompt, reasoningModel]);

    const handlePostStoryToPrompt = useCallback((storyText: string) => {
        setPrompt(storyText);
        const controlsElement = document.getElementById('controls');
        if (controlsElement) {
            controlsElement.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
    }, []);

    const isGeminiImageModel = imageModel === 'gemini-2.5-flash-image' || imageModel === 'gemini-3-pro-image-preview';

    return (
        <div className="bg-gray-900 text-white min-h-screen">
            {/* API Key Notepad Header Section */}
            <div className="w-full bg-gray-800 border-b border-gray-700 p-3 sm:p-4 sticky top-0 z-50 shadow-2xl">
                <div className="max-w-7xl mx-auto flex flex-col gap-2">
                    <div className="flex flex-wrap items-center justify-between gap-2">
                        <div className="flex items-center gap-3">
                            <label className="text-blue-400 font-bold text-sm uppercase tracking-widest flex items-center gap-2">
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z"></path></svg>
                                API key :
                            </label>
                            {statusMessage && <span className="text-xs font-semibold text-green-400 animate-pulse">{statusMessage}</span>}
                        </div>
                        <div className="flex items-center gap-2">
                            <button 
                                onClick={handleSendKey} 
                                className="px-4 py-1.5 bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold rounded shadow-md transition-all active:scale-95"
                            >
                                Send
                            </button>
                            <button 
                                onClick={handleCopyKey} 
                                className="px-4 py-1.5 bg-gray-700 hover:bg-gray-600 text-white text-xs font-bold rounded shadow-md transition-all active:scale-95"
                            >
                                Copy
                            </button>
                            <button 
                                onClick={handleClearKey} 
                                className="px-4 py-1.5 bg-red-900/40 hover:bg-red-800/60 text-red-200 text-xs font-bold rounded shadow-md transition-all active:scale-95"
                            >
                                Clear
                            </button>
                        </div>
                    </div>
                    <textarea
                        value={apiKeyInput}
                        onChange={(e) => setApiKeyInput(e.target.value)}
                        className="w-full bg-gray-950 border border-gray-700 rounded p-2 text-xs sm:text-sm text-gray-300 font-mono h-14 resize-none outline-none focus:ring-1 focus:ring-blue-500 overflow-x-auto whitespace-nowrap scrollbar-thin scrollbar-thumb-gray-700"
                        placeholder="Paste your Gemini API key here..."
                        spellCheck={false}
                    />
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                <header className="text-center mb-10">
                    <h1 className="text-4xl sm:text-5xl font-extrabold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-500 pb-2">
                        AI Image & Story Generator
                    </h1>
                    <p className="mt-3 text-lg text-gray-300">
                        stunning high-quality visuals & amazing stories by Thunyaluk AI
                    </p>
                </header>

                <main className="mb-10">
                    {loading ? (
                         <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 w-full max-w-5xl mx-auto">
                            {Array.from({ length: loadingCount }).map((_, index) => (
                                <ImagePlaceholder key={index} aspectRatio={aspectRatio} />
                            ))}
                        </div>
                    ) : images.length > 0 ? (
                        <div className={`grid ${images.length === 1 ? 'grid-cols-1' : 'sm:grid-cols-2'} gap-6 w-full ${images.length === 1 ? 'max-w-3xl' : 'max-w-5xl'} mx-auto`}>
                            {images.map((src, index) => (
                                <ImageCard
                                    key={index}
                                    src={src}
                                    index={index}
                                    aspectRatio={aspectRatio}
                                    processingAction={processingAction}
                                    onEdit={handleSetReference}
                                    onDescribe={handleDescribe}
                                    onCaption={handleCaption}
                                    onRemoveText={handleRemoveText}
                                    onExpand={handleExpandImage}
                                 />
                            ))}
                        </div>
                    ) : (
                        <div className="w-full max-w-5xl mx-auto flex flex-col items-center justify-center p-8 border-2 border-dashed border-gray-700 rounded-lg text-center text-gray-500 min-h-[300px]">
                            <svg xmlns="http://www.w3.org/2000/svg" className="mx-auto h-16 w-16" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                            </svg>
                            <h2 className="mt-4 text-2xl font-semibold text-gray-300">Your Creations Will Appear Here</h2>
                        </div>
                    )}
                </main>

                <section id="controls" className="bg-gray-800/50 backdrop-blur-md rounded-lg p-4 sm:p-6 shadow-xl max-w-4xl mx-auto border border-gray-700">
                    {error && (
                        <div className="bg-red-500/20 border border-red-500 text-red-300 px-4 py-3 rounded-lg mb-4 text-sm flex items-center">
                             <svg className="w-5 h-5 mr-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd"></path></svg>
                            <div><span className="font-bold">Error:</span> {error}</div>
                        </div>
                    )}

                    <ReferenceImages images={referenceImages} onRemove={handleRemoveReference} onUpload={handleUploadReference} onInsertTag={handleInsertRefTag} />

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">Aspect Ratio</label>
                            <select value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-2 focus:ring-2 focus:ring-blue-500 outline-none transition-all">
                                {ASPECT_RATIOS.map(ratio => <option key={ratio} value={ratio}>{ratio}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">Image Style</label>
                            <select value={style} onChange={(e) => setStyle(e.target.value as ImageStyleKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-2 focus:ring-2 focus:ring-blue-500 outline-none transition-all">
                                {IMAGE_STYLES.map(s => <option key={s.key} value={s.key}>{s.name}</option>)}
                            </select>
                        </div>
                    </div>

                    <PromptActions
                        prompt={prompt}
                        hasReferenceImage={referenceImages.length > 0}
                        onCopy={handleCopyPrompt}
                        onClear={handleClearPrompt}
                        onDescribe={handleDescribeRef1}
                        onCaption={handleCaptionRef1}
                        onRemoveText={handleRemoveTextRef1}
                        onExpand={handleExpandRef1}
                        onEnhance={handleEnhancePrompt}
                        onConcept={handleConcept}
                        loadingAction={promptActionLoading}
                    />

                    <textarea
                        ref={promptTextareaRef}
                        rows={5}
                        className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-3 mb-4 resize-none focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                        placeholder="Describe your vision..."
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                    />

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center gap-2">
                                <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9l-.707.707M12 18v1m4.243-4.243l.707.707M12 7a5 5 0 110 10 5 5 0 010-10z"></path></svg>
                                Text Reasoning Model (AI Brain)
                            </label>
                            <select value={reasoningModel} onChange={(e) => setReasoningModel(e.target.value as ReasoningModelKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-2 focus:ring-2 focus:ring-blue-400 outline-none transition-all">
                                {REASONING_MODELS.map(m => <option key={m.key} value={m.key}>{m.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center gap-2">
                                <svg className="w-4 h-4 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                                Image Model (Art Style)
                            </label>
                            <select value={imageModel} onChange={(e) => setImageModel(e.target.value as ImageModelKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-2 focus:ring-2 focus:ring-indigo-400 outline-none transition-all">
                                {IMAGE_MODELS.map(m => <option key={m.key} value={m.key}>{m.name}</option>)}
                            </select>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        <button
                            onClick={() => handleGenerate(1)}
                            disabled={loading || !prompt.trim()}
                            className={`bg-blue-600 hover:bg-blue-700 disabled:bg-gray-600 text-white font-bold py-3 rounded-md transition-all shadow-md active:scale-95 ${(isGeminiImageModel || referenceImages.length > 0) ? 'sm:col-span-2' : ''}`}
                        >
                            {loading && loadingCount === 1 ? <Spinner /> : `Generate`}
                        </button>
                        {!(isGeminiImageModel || referenceImages.length > 0) && (
                             <button
                                onClick={() => handleGenerate(4)}
                                disabled={loading || !prompt.trim()}
                                className="bg-indigo-600 hover:bg-indigo-700 disabled:bg-gray-600 text-white font-bold py-3 rounded-md transition-all shadow-md active:scale-95"
                            >
                                {loading && loadingCount === 4 ? <Spinner /> : 'Generate 4 Images'}
                            </button>
                        )}
                    </div>
                    <StoryWriter 
                        onPostToPrompt={handlePostStoryToPrompt} 
                        selectedStyle={style} 
                        selectedReasoningModel={reasoningModel} 
                        maxCaptionLength={maxCaptionLength}
                        onMaxCaptionLengthChange={setMaxCaptionLength}
                    />
                </section>
            </div>
        </div>
    );
};

export default App;

import React, { useState, useRef } from 'react';
import { STORY_LANGUAGES, STORY_STYLES, IMAGE_STYLES, StoryLanguageKey, StoryStyleKey, ImageStyleKey, ReasoningModelKey } from '../constants';
import { generateNextSentence, generateStoryCaption, polishStory, translateStory, generateDesignFromStory } from '../services/geminiService';
import Spinner from './Spinner';

interface StoryWriterProps {
    onPostToPrompt: (storyText: string) => void;
    selectedStyle: ImageStyleKey;
    selectedReasoningModel: ReasoningModelKey;
    maxCaptionLength: number;
    onMaxCaptionLengthChange: (length: number) => void;
}

const ActionButton: React.FC<{
    onClick: () => void;
    disabled?: boolean;
    isLoading?: boolean;
    children: React.ReactNode;
    title: string;
    className?: string;
}> = ({ onClick, disabled, isLoading, children, title, className = '' }) => (
    <button
        type="button"
        onClick={onClick}
        disabled={disabled || isLoading}
        title={title}
        className={`flex items-center justify-center gap-2 px-3 py-2 bg-gray-700 hover:bg-gray-600 disabled:bg-gray-700/50 disabled:cursor-not-allowed disabled:text-gray-500 text-sm text-gray-300 hover:text-white rounded-md transition-all ${className}`}
    >
        {isLoading ? <Spinner /> : children}
    </button>
);

const StoryWriter: React.FC<StoryWriterProps> = ({ 
    onPostToPrompt, 
    selectedStyle, 
    selectedReasoningModel,
    maxCaptionLength,
    onMaxCaptionLengthChange
}) => {
    const [story, setStory] = useState('');
    const [fileName, setFileName] = useState('story.txt');
    const [language, setLanguage] = useState<StoryLanguageKey>('thai');
    const [style, setStyle] = useState<StoryStyleKey>('unspecified');
    const [loadingAction, setLoadingAction] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [fileContent, setFileContent] = useState<string | null>(null);
    const [showFileOptions, setShowFileOptions] = useState(false);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const textareaRef = useRef<HTMLTextAreaElement>(null);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const text = e.target?.result as string;
                setFileContent(text);
                setShowFileOptions(true);
            };
            reader.readAsText(file);
        }
        event.target.value = '';
    };

    const handleFileOpen = (mode: 'overwrite' | 'insert' | 'append') => {
        if (!fileContent) return;

        if (mode === 'overwrite') {
            setStory(fileContent);
             if (fileInputRef.current?.files?.[0]) {
                setFileName(fileInputRef.current.files[0].name);
            }
        } else if (mode === 'append') {
            setStory(prev => (prev ? prev + '\n' : '') + fileContent);
        } else if (mode === 'insert' && textareaRef.current) {
            const { selectionStart, value } = textareaRef.current;
            const newStory = value.slice(0, selectionStart) + fileContent + value.slice(selectionStart);
            setStory(newStory);
        }
        setShowFileOptions(false);
        setFileContent(null);
    };

    const handleSaveFile = () => {
        if (!story) {
            setError("There is no story to save.");
            return;
        }
        setError(null);
        const blob = new Blob([story], { type: 'text/plain;charset=utf-8' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = fileName.endsWith('.txt') ? fileName : `${fileName}.txt`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(link.href);
    };

    const handleClear = () => setStory('');
    const handleCopy = () => navigator.clipboard.writeText(story);
    const handlePost = () => onPostToPrompt(story);

    const handleIdea = async () => {
        setLoadingAction('idea');
        setError(null);
        try {
            const nextSentence = await generateNextSentence(story, language, style, selectedReasoningModel);
            if (style === 'thai_poem') {
                setStory(prev => (prev.trim() ? prev.trim() + '\n' + nextSentence : nextSentence));
            } else {
                setStory(prev => (prev.trim() ? prev.trim() + ' ' + nextSentence : nextSentence));
            }
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handleCustomCaption = async () => {
        if (!story.trim()) {
            setError("Story is empty. Cannot create a caption.");
            return;
        }
        setLoadingAction('caption');
        setError(null);
        try {
            const caption = await generateStoryCaption(story, selectedReasoningModel, 'English', maxCaptionLength);
            const fullPrompt = `Recreate the image in [ref-1], but add the following text as a caption: "${caption}". The caption should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The text should be clear and readable on a mobile screen.`;
            onPostToPrompt(fullPrompt);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handleThaiCaption = async () => {
        if (!story.trim()) {
            setError("Story is empty. Cannot create a caption.");
            return;
        }
        setLoadingAction('caption-thai');
        setError(null);
        try {
            const caption = await generateStoryCaption(story, selectedReasoningModel, 'Thai', maxCaptionLength);
            const fullPrompt = `Recreate the image in [ref-1], but add the following text as a caption: "${caption}". The caption should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The text should be clear and readable on a mobile screen.`;
            onPostToPrompt(fullPrompt);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handleNewThaiCaption = async () => {
        if (!story.trim()) {
            setError("Story is empty. Cannot create a caption.");
            return;
        }
        setLoadingAction('new-caption-thai');
        setError(null);
        try {
            const styleName = IMAGE_STYLES.find(s => s.key === selectedStyle)?.name || 'Photorealistic';

            const [caption, designPrompt] = await Promise.all([
                generateStoryCaption(story, selectedReasoningModel, 'Thai', maxCaptionLength),
                generateDesignFromStory(story, styleName, selectedReasoningModel)
            ]);

            const fullPrompt = `${designPrompt} Text in the image: "${caption}". The caption should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The text should be clear and readable on a mobile screen.`;
            onPostToPrompt(fullPrompt);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handlePolish = async () => {
        if (!story.trim()) {
            setError("Story is empty. Nothing to polish.");
            return;
        }
        setLoadingAction('polish');
        setError(null);
        try {
            const polishedStory = await polishStory(story, selectedReasoningModel);
            onPostToPrompt(polishedStory);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handleTranslate = async (targetLanguage: 'Thai' | 'English') => {
        if (!story.trim()) {
            setError(`Story is empty. Nothing to translate to ${targetLanguage}.`);
            return;
        }
        const actionKey = `translate-${targetLanguage.toLowerCase()}`;
        setLoadingAction(actionKey);
        setError(null);
        try {
            const translatedStory = await translateStory(story, targetLanguage, selectedReasoningModel);
            onPostToPrompt(translatedStory);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };


    return (
        <div className="mt-8 border-t border-gray-700 pt-6">
            <h3 className="text-xl font-semibold text-center mb-4 text-gray-200 flex items-center justify-center gap-2">
                 <svg className="w-6 h-6 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                 Story Writer
            </h3>

            {error && (
                <div className="bg-red-500/20 border border-red-500 text-red-300 px-4 py-2 rounded-lg mb-4 text-sm">
                    {error}
                </div>
            )}

            {showFileOptions && (
                 <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50">
                    <div className="bg-gray-800 rounded-lg p-6 space-y-3 border border-gray-700 shadow-2xl">
                         <h4 className="text-lg font-semibold text-white">How to open file?</h4>
                         <button onClick={() => handleFileOpen('overwrite')} className="w-full text-left p-3 bg-gray-700 hover:bg-blue-600 rounded-md transition-colors">เขียนทับข้อมูลเดิม</button>
                         <button onClick={() => handleFileOpen('insert')} className="w-full text-left p-3 bg-gray-700 hover:bg-blue-600 rounded-md transition-colors">เขียนแทรกข้อมูลเดิม</button>
                         <button onClick={() => handleFileOpen('append')} className="w-full text-left p-3 bg-gray-700 hover:bg-blue-600 rounded-md transition-colors">เขียนต่อท้ายข้อมูลเดิม</button>
                         <button onClick={() => setShowFileOptions(false)} className="mt-2 w-full text-left p-2 bg-gray-600 hover:bg-gray-500 rounded-md text-center transition-colors">Cancel</button>
                    </div>
                 </div>
            )}

            <div className="flex flex-col sm:flex-row gap-3 mb-3">
                <button onClick={() => fileInputRef.current?.click()} className="flex-1 text-center py-2 px-4 bg-gray-700 hover:bg-gray-600 text-white rounded-md transition-colors text-sm font-medium">Open</button>
                <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".txt" />

                <input 
                    type="text"
                    value={fileName}
                    onChange={(e) => setFileName(e.target.value)}
                    className="flex-grow bg-gray-900 border border-gray-700 text-white rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 outline-none text-sm px-3"
                    placeholder="story.txt"
                />

                <button onClick={handleSaveFile} className="flex-1 text-center py-2 px-4 bg-gray-700 hover:bg-gray-600 text-white rounded-md transition-colors text-sm font-medium">Save</button>
            </div>

            <textarea
                ref={textareaRef}
                rows={10}
                className="w-full bg-gray-900 border border-gray-700 text-white rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 outline-none placeholder-gray-600 resize-y p-3 transition-all"
                placeholder="Write your story here..."
                value={story}
                onChange={(e) => setStory(e.target.value)}
                disabled={!!loadingAction}
            />

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-3 mb-4">
                <div>
                    <label htmlFor="language" className="block text-xs font-medium text-gray-400 mb-1">ภาษา</label>
                    <select id="language" value={language} onChange={(e) => setLanguage(e.target.value as StoryLanguageKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 outline-none text-sm">
                        {STORY_LANGUAGES.map(lang => <option key={lang.key} value={lang.key}>{lang.name}</option>)}
                    </select>
                </div>
                 <div>
                    <label htmlFor="style" className="block text-xs font-medium text-gray-400 mb-1">สไตล์การเล่าเรื่อง</label>
                    <select id="style" value={style} onChange={(e) => setStyle(e.target.value as StoryStyleKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 outline-none text-sm">
                        {STORY_STYLES.map(s => <option key={s.key} value={s.key}>{s.name}</option>)}
                    </select>
                </div>
            </div>

            {/* Max Caption Length Setting */}
            <div className="mb-4 flex flex-col items-center">
                 <label htmlFor="maxCaptionLength" className="text-xs font-semibold text-gray-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5">
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z"></path></svg>
                    Max Caption Length (Characters)
                 </label>
                 <input 
                    type="number"
                    id="maxCaptionLength"
                    value={maxCaptionLength}
                    onChange={(e) => onMaxCaptionLengthChange(parseInt(e.target.value) || 0)}
                    className="w-24 bg-gray-900 border border-gray-700 text-center text-blue-400 font-bold rounded-md py-1.5 outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm"
                 />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                <ActionButton onClick={handleIdea} isLoading={loadingAction === 'idea'} title="Generate the next sentence" className="bg-green-600 hover:bg-green-700 text-white font-bold">Idea</ActionButton>
                <ActionButton onClick={handleCustomCaption} isLoading={loadingAction === 'caption'} disabled={!story} title="Create an English caption for your story">Custom Caption</ActionButton>
                <ActionButton onClick={handleThaiCaption} isLoading={loadingAction === 'caption-thai'} disabled={!story} title="Create a Thai caption for your story">Thai Caption</ActionButton>
                <ActionButton onClick={handleNewThaiCaption} isLoading={loadingAction === 'new-caption-thai'} disabled={!story} title="New image with Thai caption based on story" className="bg-indigo-600 hover:bg-indigo-700 text-white">New Thai Caption</ActionButton>
                <ActionButton onClick={handlePolish} isLoading={loadingAction === 'polish'} disabled={!story} title="Rewrite the story professionally">Polish</ActionButton>
                <ActionButton onClick={handlePost} disabled={!story} title="Post story to main prompt" className="bg-blue-600 hover:bg-blue-500">Post</ActionButton>
                <ActionButton onClick={() => handleTranslate('Thai')} isLoading={loadingAction === 'translate-thai'} disabled={!story} title="Translate story to Thai and post to prompt">Thai</ActionButton>
                <ActionButton onClick={() => handleTranslate('English')} isLoading={loadingAction === 'translate-english'} disabled={!story} title="Translate story to English and post to prompt">English</ActionButton>
                <ActionButton onClick={handleCopy} disabled={!story} title="Copy story to clipboard">Copy</ActionButton>
                <ActionButton onClick={handleClear} disabled={!story} title="Clear story text">Clear</ActionButton>
            </div>

            <div className="mt-4 text-center">
                <p className="text-xs text-gray-500">
                    * ทิป: เลือกสมอง (Reasoning Model) เป็น <span className="text-blue-400">Flash</span> เพื่อประหยัดโควต้า หรือ <span className="text-indigo-400">Pro</span> เพื่อความลุ่มลึกในการต่อเนื้อเรื่อง
                </p>
            </div>
        </div>
    );
};

export default StoryWriter;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
    generateFromText, 
    generateFromImageAndText, 
    describeImage, 
    suggestCaption, 
    enhancePrompt, 
    generateConcept, 
    expandImage,
    updateActiveApiKey
} from './services/geminiService';
import { ASPECT_RATIOS, IMAGE_STYLES, IMAGE_MODELS, REASONING_MODELS, AspectRatio, ImageStyleKey, ImageModelKey, ReasoningModelKey } from './constants';
import Spinner from './components/Spinner';
import ImagePlaceholder from './components/ImagePlaceholder';
import ReferenceImages from './components/ReferenceImages';
import ImageCard from './components/ImageCard';
import { blobToBase64 } from './utils/imageUtils';
import PromptActions from './components/PromptActions';
import StoryWriter from './components/StoryWriter';

declare global {
    interface AIStudio {
        hasSelectedApiKey: () => Promise<boolean>;
        openSelectKey: () => Promise<void>;
    }
}

const App: React.FC = () => {
    // API Key Management State
    const [apiKeyInput, setApiKeyInput] = useState<string>('');
    const [statusMessage, setStatusMessage] = useState<string>('');

    const [prompt, setPrompt] = useState<string>('');
    const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
    const [style, setStyle] = useState<ImageStyleKey>('photorealistic');
    const [imageModel, setImageModel] = useState<ImageModelKey>('gemini-2.5-flash-image');
    const [reasoningModel, setReasoningModel] = useState<ReasoningModelKey>('gemini-3-flash-preview');
    const [maxCaptionLength, setMaxCaptionLength] = useState<number>(60);
    const [images, setImages] = useState<string[]>([]);
    const [referenceImages, setReferenceImages] = useState<string[]>([]);
    const [loading, setLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);
    const [loadingCount, setLoadingCount] = useState<number>(0);
    const [processingAction, setProcessingAction] = useState<string | null>(null);
    const [promptActionLoading, setPromptActionLoading] = useState<string | null>(null);
    const promptTextareaRef = useRef<HTMLTextAreaElement>(null);

    // Initialize API Key from storage or env
    useEffect(() => {
        const savedKey = localStorage.getItem('user_api_key');
        const defaultKey = process.env.API_KEY;

        if (savedKey) {
            setApiKeyInput(savedKey);
            updateActiveApiKey(savedKey);
        } else if (defaultKey && defaultKey !== 'PLACEHOLDER_API_KEY' && defaultKey.length > 5) {
            setApiKeyInput(defaultKey);
            updateActiveApiKey(defaultKey);
        } else {
            setApiKeyInput('no API key');
        }
    }, []);

    const handleSendKey = () => {
        if (!apiKeyInput || apiKeyInput === 'no API key' || apiKeyInput.trim() === '') {
            setError("Please enter a valid API key.");
            return;
        }
        localStorage.setItem('user_api_key', apiKeyInput.trim());
        updateActiveApiKey(apiKeyInput.trim());
        setStatusMessage("Applied & Saved!");
        setTimeout(() => setStatusMessage(""), 3000);
    };

    const handleCopyKey = () => {
        if (apiKeyInput && apiKeyInput !== 'no API key') {
            navigator.clipboard.writeText(apiKeyInput);
            setStatusMessage("Copied!");
            setTimeout(() => setStatusMessage(""), 2000);
        }
    };

    const handleClearKey = () => {
        setApiKeyInput('');
        localStorage.removeItem('user_api_key');
        updateActiveApiKey(process.env.API_KEY || '');
        setStatusMessage("Cleared.");
        setTimeout(() => setStatusMessage(""), 2000);
    };

    const handleGenerate = useCallback(async (count: 1 | 4) => {
        if (!prompt.trim()) {
            setError("Please enter a prompt.");
            return;
        }

        const hasKey = localStorage.getItem('user_api_key') || (process.env.API_KEY && process.env.API_KEY !== 'PLACEHOLDER_API_KEY');
        if (!hasKey && imageModel === 'gemini-3-pro-image-preview') {
            try {
                const nativeKey = await window.aistudio.hasSelectedApiKey();
                if (!nativeKey) await window.aistudio.openSelectKey();
            } catch (err) {
                setError("API Key is required. Please set it in the field above.");
                return;
            }
        }

        setLoading(true);
        setError(null);
        setImages([]);

        const isGeminiModel = imageModel === 'gemini-2.5-flash-image' || imageModel === 'gemini-3-pro-image-preview';
        let effectiveCount = (referenceImages.length > 0 || isGeminiModel) ? 1 : count;
        setLoadingCount(effectiveCount);

        try {
            let generatedImages: string[];
            if (referenceImages.length > 0) {
                 generatedImages = await generateFromImageAndText(prompt, referenceImages);
            } else {
                 generatedImages = await generateFromText(prompt, effectiveCount as 1 | 4, aspectRatio, style, imageModel);
            }
            setImages(generatedImages);
        } catch (err) {
            if (err instanceof Error) {
                if (err.message.includes("Requested entity was not found") || err.message.includes("API_KEY_INVALID")) {
                     try {
                        setError("Invalid API Key. Please update the key in the field above.");
                        const controls = document.body;
                        controls.scrollIntoView({ behavior: 'smooth', block: 'start' });
                    } catch (e) {
                        setError("API Error: " + err.message);
                    }
                } else {
                    setError(err.message);
                }
            } else {
                setError("An unknown error occurred.");
            }
        } finally {
            setLoading(false);
            setLoadingCount(0);
        }
    }, [prompt, aspectRatio, style, imageModel, referenceImages]);

    const handleSetReference = useCallback((imageSrc: string) => {
        if (referenceImages.length < 4) {
            setReferenceImages(prev => [...prev, imageSrc]);
        } else {
            setError("You can only have a maximum of 4 reference images.");
        }
    }, [referenceImages.length]);

    const handleRemoveReference = useCallback((indexToRemove: number) => {
        setReferenceImages(prev => prev.filter((_, index) => index !== indexToRemove));
    }, []);

    const handleUploadReference = useCallback(async (file: File) => {
        if (!file.type.startsWith('image/')) {
            setError("Please upload a valid image file.");
            return;
        }
        try {
            const base64 = await blobToBase64(file);
            handleSetReference(base64 as string);
        } catch (err) {
            setError("Failed to read the image file.");
        }
    }, [handleSetReference]);

    const handleInsertRefTag = useCallback((tag: string) => {
        const textarea = promptTextareaRef.current;
        if (textarea) {
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const text = textarea.value;
            const newText = `${text.substring(0, start)} ${tag} ${text.substring(end)}`;
            setPrompt(newText);
            textarea.focus();
            textarea.selectionStart = textarea.selectionEnd = start + tag.length + 2;
        }
    }, []);

    const handleDescribe = useCallback(async (imageSrc: string, index: number) => {
        setProcessingAction(`describe-${index}`);
        setError(null);
        try {
            const description = await describeImage(imageSrc, reasoningModel);
            setPrompt(description);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setProcessingAction(null);
        }
    }, [reasoningModel]);

    const handleCaption = useCallback(async (imageSrc: string, index: number) => {
        setProcessingAction(`caption-${index}`);
        setError(null);
        try {
            const caption = await suggestCaption(imageSrc, reasoningModel, maxCaptionLength);
            setReferenceImages([imageSrc]);
            const isThai = /[ก-ฮ]/.test(caption);
            const textType = isThai ? "Thai text" : "text";
            setPrompt(`Recreate the image in [ref-1], but add the following ${textType} as a caption: "${caption}". The ${textType} should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The ${textType} MUST be clear and readable, using the exact characters provided without translation.`);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setProcessingAction(null);
        }
    }, [reasoningModel, maxCaptionLength]);

    const handleRemoveText = useCallback(async (imageSrc: string, index: number) => {
        setProcessingAction(`remove-text-${index}`);
        setError(null);
        const newPrompt = `Analyze the image provided in [ref-1] and remove all text, words, characters and logos. Reconstruct the areas where the text was removed to look natural and seamless with the rest of the image.`;
        const newReferenceImages = [imageSrc];
        setPrompt(newPrompt);
        setReferenceImages(newReferenceImages);
        setLoading(true);
        setImages([]);
        setLoadingCount(1);
        try {
            const generatedImages = await generateFromImageAndText(newPrompt, newReferenceImages);
            setImages(generatedImages);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoading(false);
            setLoadingCount(0);
            setProcessingAction(null);
        }
    }, []);

    const handleExpandImage = useCallback(async (imageSrc: string, index: number, targetAspectRatio: AspectRatio) => {
        setProcessingAction(`expand-${index}`);
        setLoading(true);
        setError(null);
        setImages([]);
        setLoadingCount(1);
        setAspectRatio(targetAspectRatio);
        try {
            const expandedImages = await expandImage(imageSrc, targetAspectRatio);
            setImages(expandedImages);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoading(false);
            setLoadingCount(0);
            setProcessingAction(null);
            setAspectRatio('16:9');
        }
    }, []);

    const handleCopyPrompt = () => {
        if (!prompt.trim()) return;
        navigator.clipboard.writeText(prompt);
    };

    const handleClearPrompt = () => {
        setPrompt('');
    };

    const handleDescribeRef1 = useCallback(async () => {
        if (referenceImages.length === 0) {
            setError("No reference image available to describe.");
            return;
        }
        setPromptActionLoading('describe-ref-1');
        setError(null);
        try {
            const description = await describeImage(referenceImages[0], reasoningModel);
            setPrompt(description);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setPromptActionLoading(null);
        }
    }, [referenceImages, reasoningModel]);

    const handleCaptionRef1 = useCallback(async () => {
        if (referenceImages.length === 0) {
            setError("No reference image available to caption.");
            return;
        }
        setPromptActionLoading('caption-ref-1');
        setError(null);
        try {
            const caption = await suggestCaption(referenceImages[0], reasoningModel, maxCaptionLength);
            setReferenceImages([referenceImages[0]]);
            const isThai = /[ก-ฮ]/.test(caption);
            const textType = isThai ? "Thai text" : "text";
            setPrompt(`Recreate the image in [ref-1], but add the following ${textType} as a caption: "${caption}". The ${textType} should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The ${textType} MUST be clear and readable, using the exact characters provided without translation.`);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setPromptActionLoading(null);
        }
    }, [referenceImages, reasoningModel, maxCaptionLength]);

    const handleRemoveTextRef1 = useCallback(async () => {
        if (referenceImages.length === 0) {
            setError("No reference image available to process.");
            return;
        }
        setPromptActionLoading('remove-text-ref-1');
        setError(null);
        const newPrompt = `Analyze the image provided in [ref-1] and remove all text, words, characters and logos. Reconstruct the areas where the text was removed to look natural and seamless with the rest of the image.`;
        const newReferenceImages = [referenceImages[0]];
        setPrompt(newPrompt);
        setReferenceImages(newReferenceImages);
        setLoading(true);
        setImages([]);
        setLoadingCount(1);
        try {
            const generatedImages = await generateFromImageAndText(newPrompt, newReferenceImages);
            setImages(generatedImages);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoading(false);
            setLoadingCount(0);
            setPromptActionLoading(null);
        }
    }, [referenceImages]);

    const handleExpandRef1 = useCallback(async (targetAspectRatio: AspectRatio) => {
        if (referenceImages.length === 0) {
            setError("No reference image available to expand.");
            return;
        }
        setPromptActionLoading('expand-ref-1');
        setLoading(true);
        setError(null);
        setImages([]);
        setLoadingCount(1);
        setAspectRatio(targetAspectRatio);
        try {
            const expandedImages = await expandImage(referenceImages[0], targetAspectRatio);
            setImages(expandedImages);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoading(false);
            setLoadingCount(0);
            setPromptActionLoading(null);
            setAspectRatio('16:9');
        }
    }, [referenceImages]);

    const handleEnhancePrompt = useCallback(async () => {
        if (!prompt.trim()) {
            setError("Prompt is empty, nothing to enhance.");
            return;
        }
        setPromptActionLoading('enhance');
        setError(null);
        try {
            const enhanced = await enhancePrompt(prompt, reasoningModel);
            setPrompt(enhanced);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setPromptActionLoading(null);
        }
