                    />
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                <header className="text-center mb-10">
                    <h1 className="text-4xl sm:text-5xl font-extrabold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-500 pb-2">
                        AI Image & Story Generator
                    </h1>
                    <p className="mt-3 text-lg text-gray-300">
                        stunning high-quality visuals & amazing stories by Thunyaluk AI
                    </p>
                </header>

                <main className="mb-10">
                    {loading ? (
                         <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 w-full max-w-5xl mx-auto">
                            {Array.from({ length: loadingCount }).map((_, index) => (
                                <ImagePlaceholder key={index} aspectRatio={aspectRatio} />
                            ))}
                        </div>
                    ) : images.length > 0 ? (
                        <div className={`grid ${images.length === 1 ? 'grid-cols-1' : 'sm:grid-cols-2'} gap-6 w-full ${images.length === 1 ? 'max-w-3xl' : 'max-w-5xl'} mx-auto`}>
                            {images.map((src, index) => (
                                <ImageCard
                                    key={index}
                                    src={src}
                                    index={index}
                                    aspectRatio={aspectRatio}
                                    processingAction={processingAction}
                                    onEdit={handleSetReference}
                                    onDescribe={handleDescribe}
                                    onCaption={handleCaption}
                                    onRemoveText={handleRemoveText}
                                    onExpand={handleExpandImage}
                                 />
                            ))}
                        </div>
                    ) : (
                        <div className="w-full max-w-5xl mx-auto flex flex-col items-center justify-center p-8 border-2 border-dashed border-gray-700 rounded-lg text-center text-gray-500 min-h-[300px]">
                            <svg xmlns="http://www.w3.org/2000/svg" className="mx-auto h-16 w-16" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                            </svg>
                            <h2 className="mt-4 text-2xl font-semibold text-gray-300">Your Creations Will Appear Here</h2>
                        </div>
                    )}
                </main>

                <section id="controls" className="bg-gray-800/50 backdrop-blur-md rounded-lg p-4 sm:p-6 shadow-xl max-w-4xl mx-auto border border-gray-700">
                    {error && (
                        <div className="bg-red-500/20 border border-red-500 text-red-300 px-4 py-3 rounded-lg mb-4 text-sm flex items-center">
                             <svg className="w-5 h-5 mr-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd"></path></svg>
                            <div><span className="font-bold">Error:</span> {error}</div>
                        </div>
                    )}

                    <ReferenceImages images={referenceImages} onRemove={handleRemoveReference} onUpload={handleUploadReference} onInsertTag={handleInsertRefTag} />

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">Aspect Ratio</label>
                            <select value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-2 focus:ring-2 focus:ring-blue-500 outline-none transition-all">
                                {ASPECT_RATIOS.map(ratio => <option key={ratio} value={ratio}>{ratio}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1">Image Style</label>
                            <select value={style} onChange={(e) => setStyle(e.target.value as ImageStyleKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-2 focus:ring-2 focus:ring-blue-500 outline-none transition-all">
                                {IMAGE_STYLES.map(s => <option key={s.key} value={s.key}>{s.name}</option>)}
                            </select>
                        </div>
                    </div>

                    <PromptActions
                        prompt={prompt}
                        hasReferenceImage={referenceImages.length > 0}
                        onCopy={handleCopyPrompt}
                        onClear={handleClearPrompt}
                        onDescribe={handleDescribeRef1}
                        onCaption={handleCaptionRef1}
                        onRemoveText={handleRemoveTextRef1}
                        onExpand={handleExpandRef1}
                        onEnhance={handleEnhancePrompt}
                        onConcept={handleConcept}
                        loadingAction={promptActionLoading}
                    />

                    <textarea
                        ref={promptTextareaRef}
                        rows={5}
                        className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-3 mb-4 resize-none focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                        placeholder="Describe your vision..."
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                    />

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center gap-2">
                                <svg className="w-4 h-4 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9l-.707.707M12 18v1m4.243-4.243l.707.707M12 7a5 5 0 110 10 5 5 0 010-10z"></path></svg>
                                Text Reasoning Model (AI Brain)
                            </label>
                            <select value={reasoningModel} onChange={(e) => setReasoningModel(e.target.value as ReasoningModelKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-2 focus:ring-2 focus:ring-blue-400 outline-none transition-all">
                                {REASONING_MODELS.map(m => <option key={m.key} value={m.key}>{m.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center gap-2">
                                <svg className="w-4 h-4 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                                Image Model (Art Style)
                            </label>
                            <select value={imageModel} onChange={(e) => setImageModel(e.target.value as ImageModelKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md p-2 focus:ring-2 focus:ring-indigo-400 outline-none transition-all">
                                {IMAGE_MODELS.map(m => <option key={m.key} value={m.key}>{m.name}</option>)}
                            </select>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        <button
                            onClick={() => handleGenerate(1)}
                            disabled={loading || !prompt.trim()}
                            className={`bg-blue-600 hover:bg-blue-700 disabled:bg-gray-600 text-white font-bold py-3 rounded-md transition-all shadow-md active:scale-95 ${(isGeminiImageModel || referenceImages.length > 0) ? 'sm:col-span-2' : ''}`}
                        >
                            {loading && loadingCount === 1 ? <Spinner /> : `Generate`}
                        </button>
                        {!(isGeminiImageModel || referenceImages.length > 0) && (
                             <button
                                onClick={() => handleGenerate(4)}
                                disabled={loading || !prompt.trim()}
                                className="bg-indigo-600 hover:bg-indigo-700 disabled:bg-gray-600 text-white font-bold py-3 rounded-md transition-all shadow-md active:scale-95"
                            >
                                {loading && loadingCount === 4 ? <Spinner /> : 'Generate 4 Images'}
                            </button>
                        )}
                    </div>
                    <StoryWriter 
                        onPostToPrompt={handlePostStoryToPrompt} 
                        selectedStyle={style} 
                        selectedReasoningModel={reasoningModel} 
                        maxCaptionLength={maxCaptionLength}
                        onMaxCaptionLengthChange={setMaxCaptionLength}
                    />
                </section>
            </div>
        </div>
    );
};

export default App;

import React, { useState, useRef } from 'react';
import { STORY_LANGUAGES, STORY_STYLES, IMAGE_STYLES, StoryLanguageKey, StoryStyleKey, ImageStyleKey, ReasoningModelKey } from '../constants';
import { generateNextSentence, generateStoryCaption, polishStory, translateStory, generateDesignFromStory } from '../services/geminiService';
import Spinner from './Spinner';

interface StoryWriterProps {
    onPostToPrompt: (storyText: string) => void;
    selectedStyle: ImageStyleKey;
    selectedReasoningModel: ReasoningModelKey;
    maxCaptionLength: number;
    onMaxCaptionLengthChange: (length: number) => void;
}

const ActionButton: React.FC<{
    onClick: () => void;
    disabled?: boolean;
    isLoading?: boolean;
    children: React.ReactNode;
    title: string;
    className?: string;
}> = ({ onClick, disabled, isLoading, children, title, className = '' }) => (
    <button
        type="button"
        onClick={onClick}
        disabled={disabled || isLoading}
        title={title}
        className={`flex items-center justify-center gap-2 px-3 py-2 bg-gray-700 hover:bg-gray-600 disabled:bg-gray-700/50 disabled:cursor-not-allowed disabled:text-gray-500 text-sm text-gray-300 hover:text-white rounded-md transition-all ${className}`}
    >
        {isLoading ? <Spinner /> : children}
    </button>
);

const StoryWriter: React.FC<StoryWriterProps> = ({ 
    onPostToPrompt, 
    selectedStyle, 
    selectedReasoningModel,
    maxCaptionLength,
    onMaxCaptionLengthChange
}) => {
    const [story, setStory] = useState('');
    const [fileName, setFileName] = useState('story.txt');
    const [language, setLanguage] = useState<StoryLanguageKey>('thai');
    const [style, setStyle] = useState<StoryStyleKey>('unspecified');
    const [loadingAction, setLoadingAction] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [fileContent, setFileContent] = useState<string | null>(null);
    const [showFileOptions, setShowFileOptions] = useState(false);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const textareaRef = useRef<HTMLTextAreaElement>(null);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (e) => {
                const text = e.target?.result as string;
                setFileContent(text);
                setShowFileOptions(true);
            };
            reader.readAsText(file);
        }
        event.target.value = '';
    };

    const handleFileOpen = (mode: 'overwrite' | 'insert' | 'append') => {
        if (!fileContent) return;

        if (mode === 'overwrite') {
            setStory(fileContent);
             if (fileInputRef.current?.files?.[0]) {
                setFileName(fileInputRef.current.files[0].name);
            }
        } else if (mode === 'append') {
            setStory(prev => (prev ? prev + '\n' : '') + fileContent);
        } else if (mode === 'insert' && textareaRef.current) {
            const { selectionStart, value } = textareaRef.current;
            const newStory = value.slice(0, selectionStart) + fileContent + value.slice(selectionStart);
            setStory(newStory);
        }
        setShowFileOptions(false);
        setFileContent(null);
    };

    const handleSaveFile = () => {
        if (!story) {
            setError("There is no story to save.");
            return;
        }
        setError(null);
        const blob = new Blob([story], { type: 'text/plain;charset=utf-8' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = fileName.endsWith('.txt') ? fileName : `${fileName}.txt`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(link.href);
    };

    const handleClear = () => setStory('');
    const handleCopy = () => navigator.clipboard.writeText(story);
    const handlePost = () => onPostToPrompt(story);

    const handleIdea = async () => {
        setLoadingAction('idea');
        setError(null);
        try {
            const nextSentence = await generateNextSentence(story, language, style, selectedReasoningModel);
            if (style === 'thai_poem') {
                setStory(prev => (prev.trim() ? prev.trim() + '\n' + nextSentence : nextSentence));
            } else {
                setStory(prev => (prev.trim() ? prev.trim() + ' ' + nextSentence : nextSentence));
            }
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handleCustomCaption = async () => {
        if (!story.trim()) {
            setError("Story is empty. Cannot create a caption.");
            return;
        }
        setLoadingAction('caption');
        setError(null);
        try {
            const caption = await generateStoryCaption(story, selectedReasoningModel, 'English', maxCaptionLength);
            const fullPrompt = `Recreate the image in [ref-1], but add the following text as a caption: "${caption}". The text should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The text should be clear and readable on a mobile screen. Use the exact text provided without translation.`;
            onPostToPrompt(fullPrompt);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handleThaiCaption = async () => {
        if (!story.trim()) {
            setError("Story is empty. Cannot create a caption.");
            return;
        }
        setLoadingAction('caption-thai');
        setError(null);
        try {
            const caption = await generateStoryCaption(story, selectedReasoningModel, 'Thai', maxCaptionLength);
            const fullPrompt = `Recreate the image in [ref-1], but add the following Thai text as a caption: "${caption}". The Thai text should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The Thai text MUST be rendered exactly as written in Thai characters, without any translation to English.`;
            onPostToPrompt(fullPrompt);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handleNewThaiCaption = async () => {
        if (!story.trim()) {
            setError("Story is empty. Cannot create a caption.");
            return;
        }
        setLoadingAction('new-caption-thai');
        setError(null);
        try {
            const styleName = IMAGE_STYLES.find(s => s.key === selectedStyle)?.name || 'Photorealistic';

            const [caption, designPrompt] = await Promise.all([
                generateStoryCaption(story, selectedReasoningModel, 'Thai', maxCaptionLength),
                generateDesignFromStory(story, styleName, selectedReasoningModel)
            ]);

            const fullPrompt = `${designPrompt} Thai text in the image: "${caption}". The Thai text should be elegantly placed in a suitable position, using a beautiful font with a color that is easily readable against the background. Do not obscure important details like faces or key subjects. The Thai text MUST be rendered exactly as written in Thai characters, without any translation to English.`;
            onPostToPrompt(fullPrompt);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handlePolish = async () => {
        if (!story.trim()) {
            setError("Story is empty. Nothing to polish.");
            return;
        }
        setLoadingAction('polish');
        setError(null);
        try {
            const polishedStory = await polishStory(story, selectedReasoningModel);
            onPostToPrompt(polishedStory);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };

    const handleTranslate = async (targetLanguage: 'Thai' | 'English') => {
        if (!story.trim()) {
            setError(`Story is empty. Nothing to translate to ${targetLanguage}.`);
            return;
        }
        const actionKey = `translate-${targetLanguage.toLowerCase()}`;
        setLoadingAction(actionKey);
        setError(null);
        try {
            const translatedStory = await translateStory(story, targetLanguage, selectedReasoningModel);
            onPostToPrompt(translatedStory);
        } catch (err) {
            setError((err as Error).message);
        } finally {
            setLoadingAction(null);
        }
    };


    return (
        <div className="mt-8 border-t border-gray-700 pt-6">
            <h3 className="text-xl font-semibold text-center mb-4 text-gray-200 flex items-center justify-center gap-2">
                 <svg className="w-6 h-6 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                 Story Writer
            </h3>

            {error && (
                <div className="bg-red-500/20 border border-red-500 text-red-300 px-4 py-2 rounded-lg mb-4 text-sm">
                    {error}
                </div>
            )}

            {showFileOptions && (
                 <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50">
                    <div className="bg-gray-800 rounded-lg p-6 space-y-3 border border-gray-700 shadow-2xl">
                         <h4 className="text-lg font-semibold text-white">How to open file?</h4>
                         <button onClick={() => handleFileOpen('overwrite')} className="w-full text-left p-3 bg-gray-700 hover:bg-blue-600 rounded-md transition-colors">เขียนทับข้อมูลเดิม</button>
                         <button onClick={() => handleFileOpen('insert')} className="w-full text-left p-3 bg-gray-700 hover:bg-blue-600 rounded-md transition-colors">เขียนแทรกข้อมูลเดิม</button>
                         <button onClick={() => handleFileOpen('append')} className="w-full text-left p-3 bg-gray-700 hover:bg-blue-600 rounded-md transition-colors">เขียนต่อท้ายข้อมูลเดิม</button>
                         <button onClick={() => setShowFileOptions(false)} className="mt-2 w-full text-left p-2 bg-gray-600 hover:bg-gray-500 rounded-md text-center transition-colors">Cancel</button>
                    </div>
                 </div>
            )}

            <div className="flex flex-col sm:flex-row gap-3 mb-3">
                <button onClick={() => fileInputRef.current?.click()} className="flex-1 text-center py-2 px-4 bg-gray-700 hover:bg-gray-600 text-white rounded-md transition-colors text-sm font-medium">Open</button>
                <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".txt" />

                <input 
                    type="text"
                    value={fileName}
                    onChange={(e) => setFileName(e.target.value)}
                    className="flex-grow bg-gray-900 border border-gray-700 text-white rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 outline-none text-sm px-3"
                    placeholder="story.txt"
                />

                <button onClick={handleSaveFile} className="flex-1 text-center py-2 px-4 bg-gray-700 hover:bg-gray-600 text-white rounded-md transition-colors text-sm font-medium">Save</button>
            </div>

            <textarea
                ref={textareaRef}
                rows={10}
                className="w-full bg-gray-900 border border-gray-700 text-white rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 outline-none placeholder-gray-600 resize-y p-3 transition-all"
                placeholder="Write your story here..."
                value={story}
                onChange={(e) => setStory(e.target.value)}
                disabled={!!loadingAction}
            />

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-3 mb-4">
                <div>
                    <label htmlFor="language" className="block text-xs font-medium text-gray-400 mb-1">ภาษา</label>
                    <select id="language" value={language} onChange={(e) => setLanguage(e.target.value as StoryLanguageKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 outline-none text-sm">
                        {STORY_LANGUAGES.map(lang => <option key={lang.key} value={lang.key}>{lang.name}</option>)}
                    </select>
                </div>
                 <div>
                    <label htmlFor="style" className="block text-xs font-medium text-gray-400 mb-1">สไตล์การเล่าเรื่อง</label>
                    <select id="style" value={style} onChange={(e) => setStyle(e.target.value as StoryStyleKey)} className="w-full bg-gray-700 border-gray-600 text-white rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 outline-none text-sm">
                        {STORY_STYLES.map(s => <option key={s.key} value={s.key}>{s.name}</option>)}
                    </select>
                </div>
            </div>

            {/* Max Caption Length Setting */}
            <div className="mb-4 flex flex-col items-center">
                 <label htmlFor="maxCaptionLength" className="text-xs font-semibold text-gray-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5">
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 8h10M7 12h4m1 8l-4-4H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-3l-4 4z"></path></svg>
                    Max Caption Length (Characters)
                 </label>
                 <input 
                    type="number"
                    id="maxCaptionLength"
                    value={maxCaptionLength}
                    onChange={(e) => onMaxCaptionLengthChange(parseInt(e.target.value) || 0)}
                    className="w-24 bg-gray-900 border border-gray-700 text-center text-blue-400 font-bold rounded-md py-1.5 outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm"
                 />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
                <ActionButton onClick={handleIdea} isLoading={loadingAction === 'idea'} title="Generate the next sentence" className="bg-green-600 hover:bg-green-700 text-white font-bold">Idea</ActionButton>
                <ActionButton onClick={handleCustomCaption} isLoading={loadingAction === 'caption'} disabled={!story} title="Create an English caption for your story">Custom Caption</ActionButton>
                <ActionButton onClick={handleThaiCaption} isLoading={loadingAction === 'caption-thai'} disabled={!story} title="Create a Thai caption for your story">Thai Caption</ActionButton>
                <ActionButton onClick={handleNewThaiCaption} isLoading={loadingAction === 'new-caption-thai'} disabled={!story} title="New image with Thai caption based on story" className="bg-indigo-600 hover:bg-indigo-700 text-white">New Thai Caption</ActionButton>
                <ActionButton onClick={handlePolish} isLoading={loadingAction === 'polish'} disabled={!story} title="Rewrite the story professionally">Polish</ActionButton>
                <ActionButton onClick={handlePost} disabled={!story} title="Post story to main prompt" className="bg-blue-600 hover:bg-blue-500">Post</ActionButton>
                <ActionButton onClick={() => handleTranslate('Thai')} isLoading={loadingAction === 'translate-thai'} disabled={!story} title="Translate story to Thai and post to prompt">Thai</ActionButton>
                <ActionButton onClick={() => handleTranslate('English')} isLoading={loadingAction === 'translate-english'} disabled={!story} title="Translate story to English and post to prompt">English</ActionButton>
                <ActionButton onClick={handleCopy} disabled={!story} title="Copy story to clipboard">Copy</ActionButton>
                <ActionButton onClick={handleClear} disabled={!story} title="Clear story text">Clear</ActionButton>
            </div>

            <div className="mt-4 text-center">
                <p className="text-xs text-gray-500">
                    * ทิป: เลือกสมอง (Reasoning Model) เป็น <span className="text-blue-400">Flash</span> เพื่อประหยัดโควต้า หรือ <span className="text-indigo-400">Pro</span> เพื่อความลุ่มลึกในการต่อเนื้อเรื่อง
                </p>
            </div>
        </div>
    );
};

export default StoryWriter;

import React, { useState, useRef, useEffect } from 'react';
import Spinner from './Spinner';
import { ASPECT_RATIOS, AspectRatio } from '../constants';

interface PromptActionsProps {
    prompt: string;
    hasReferenceImage: boolean;
    onCopy: () => void;
    onClear: () => void;
    onDescribe: () => void;
    onCaption: () => void;
    onRemoveText: () => void;
    onExpand: (ratio: AspectRatio) => void;
    onEnhance: () => void;
    onConcept: () => void;
    loadingAction: string | null;
}

const ActionButton: React.FC<{
    onClick: () => void;
    disabled?: boolean;
    isLoading?: boolean;
    children: React.ReactNode;
    title: string;
    className?: string;
}> = ({ onClick, disabled, isLoading, children, title, className = '' }) => (
    <button
        type="button"
        onClick={onClick}
        disabled={disabled || isLoading}
        title={title}
        className={`flex items-center justify-center gap-2 px-3 py-2 bg-gray-700 hover:bg-gray-600 disabled:bg-gray-700/50 disabled:cursor-not-allowed disabled:text-gray-500 text-sm text-gray-300 hover:text-white rounded-md transition-all ${className}`}
    >
        {isLoading ? <Spinner /> : children}
    </button>
);


const PromptActions: React.FC<PromptActionsProps> = ({
    prompt,
    hasReferenceImage,
    onCopy,
    onClear,
    onDescribe,
    onCaption,
    onRemoveText,
    onExpand,
    onEnhance,
    onConcept,
    loadingAction,
}) => {
    const [showExpandMenu, setShowExpandMenu] = useState(false);
    const expandMenuRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (expandMenuRef.current && !expandMenuRef.current.contains(event.target as Node)) {
                setShowExpandMenu(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, []);

    const openLink = (url: string) => {
        window.open(url, '_blank');
    };

    return (
        <div className="mb-4 flex flex-wrap gap-2 justify-center">
            <ActionButton
                onClick={onCopy}
                disabled={!prompt}
                title="Copy prompt to clipboard"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
                Copy
            </ActionButton>
            <ActionButton
                onClick={onClear}
                disabled={!prompt}
                title="Clear prompt"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                Clear
            </ActionButton>
            <ActionButton
                onClick={onDescribe}
                disabled={!hasReferenceImage}
                isLoading={loadingAction === 'describe-ref-1'}
                title="Describe ref-1 to generate a prompt"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z"/><circle cx="12" cy="12" r="3"/></svg>
                Describe Image
            </ActionButton>
             <ActionButton
                onClick={onCaption}
                disabled={!hasReferenceImage}
                isLoading={loadingAction === 'caption-ref-1'}
                title="Suggest a caption for ref-1 and create a prompt"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                Caption
            </ActionButton>
            <ActionButton
                onClick={onRemoveText}
                disabled={!hasReferenceImage}
                isLoading={loadingAction === 'remove-text-ref-1'}
                title="Remove text from ref-1 and generate"
            >
                 <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m7 21-4.3-4.3c-1-1-1-2.5 0-3.4l9.6-9.6c1-1 2.5-1 3.4 0l5.6 5.6c1 1 1 2.5 0 3.4L13 21"/><path d="M22 21H7"/><path d="m5 12 5 5"/></svg>
                Remove Text
            </ActionButton>
            <div className="relative" ref={expandMenuRef}>
                 <ActionButton
                    onClick={() => setShowExpandMenu(prev => !prev)}
                    disabled={!hasReferenceImage}
                    isLoading={loadingAction === 'expand-ref-1'}
                    title="Expand ref-1 to a new aspect ratio"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14.5 9.5 21 3m0 0h-6m6 0v6M9.5 14.5 3 21m0 0h6m-6 0v-6"/></svg>
                    Expand
                </ActionButton>
                {showExpandMenu && (
                     <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-max bg-gray-800 border border-gray-600 rounded-md shadow-lg z-10 p-1">
                        {ASPECT_RATIOS.map(ratio => (
                            <button
                                key={ratio}
                                onClick={() => {
                                    onExpand(ratio);
                                    setShowExpandMenu(false);
                                }}
                                className="block w-full text-left px-3 py-1.5 text-sm text-gray-300 hover:bg-blue-600 hover:text-white rounded-sm transition-colors"
                            >
                                Expand to {ratio}
                            </button>
                        ))}
                    </div>
                )}
            </div>
             <ActionButton
                onClick={onEnhance}
                disabled={!prompt}
                isLoading={loadingAction === 'enhance'}
                title="Enhance the current prompt with more detail"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.9 5.8-5.8 1.9 5.8 1.9 1.9 5.8 1.9-5.8 5.8-1.9-5.8-1.9Z"/></svg>
                Enhance Prompt
            </ActionButton>
             <ActionButton
                onClick={onConcept}
                disabled={!prompt}
                isLoading={loadingAction === 'concept'}
                title="Generate an image concept from your story"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M15 14c.2-1 .7-1.7 1.5-2.5 1-.9 1.5-2.2 1.5-3.5A6 6 0 0 0 6 8c0 1 .2 2.2 1.5 3.5.7.7 1.3 1.5 1.5 2.5"/><path d="M9 18h6"/><path d="M10 22h4"/></svg>
                Concept
            </ActionButton>

            {/* External Tool Buttons */}
            <ActionButton
                onClick={() => openLink('https://labs.google/fx/th/tools/flow')}
                title="Open Google Labs Flow"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 12c0-5.52-4.48-10-10-10S2 6.48 2 12s4.48 10 10 10 10-4.48 10-10z"/><path d="M14.31 8l5.74 9.94M9.69 8h11.48M7.38 12l5.74-9.94M9.69 16L3.95 6.06M14.31 16H2.83M16.62 12l-5.74 9.94"/></svg>
                Flow
            </ActionButton>

             <ActionButton
                onClick={() => openLink('https://labs.google/fx/th/tools/whisk')}
                title="Open Google Labs Whisk"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 14 4-4"/><path d="M3.34 19a10 10 0 1 1 17.32 0"/></svg>
                Whisk
            </ActionButton>

             <ActionButton
                onClick={() => openLink('https://labs.google')}
                title="Open Google Labs"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M10 2v7.31"/><path d="M14 2v7.31"/><path d="M8.5 2h7"/><path d="M14 9.3a6.5 6.5 0 1 1-4 0"/><path d="M5.52 16h12.96"/></svg>
                Lab
            </ActionButton>

            <ActionButton
                onClick={() => openLink('https://gemini.google.com/')}
                title="Open Google Gemini"
            >
                 <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
                Gemini
            </ActionButton>
        </div>
    );
};

export default PromptActions;
